def rl_backup(backup_type: str, transitions, gamma: float, values: dict, policy: dict = None) -> float:
    def action_value_backup(trans_list):
        """Q(s,a) = sum_s' P(s'|s,a) * [R + gamma * V(s')]"""
        total = 0.0
        for prob, next_state, reward in trans_list:
            v_next = values.get(next_state, 0.0)
            total += prob * (reward + gamma * v_next)
        return total

    if backup_type == 'action_value':
        result = action_value_backup(transitions)

    elif backup_type == 'state_value':
        # V(s) = sum_a pi(a|s) * Q(s,a)
        result = 0.0
        for action, prob_action in policy.items():
            trans_list = transitions[action]
            q_sa = action_value_backup(trans_list)
            result += prob_action * q_sa

    elif backup_type == 'optimal_value':
        # V*(s) = max_a Q(s,a)
        q_values = [action_value_backup(trans_list) for trans_list in transitions.values()]
        result = max(q_values)

    else:
        raise ValueError(f"Unknown backup_type: {backup_type}")

    return round(result, 4)
